external_knowledge:
- 'A loyal fan base' refers to fans who have been registered for over 100 days and have supported their teams in non-scheduled matches;
- 'Stood by their teams for more than 100 days' means the difference between the current date and the fan's registration date is greater than 100 days;
- 'Cheered them on in non-scheduled matches' implies matches that are not in the 'scheduled' status.

sql:
SELECT *
FROM matches
WHERE home_team_score > away_team_score;
